effect.shader:
void main() {

    vec2 adjOffs = offs / 1000.0;
    adjOffs.x *= acLayerSize.x/acLayerSize.y * -1.0;
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    float p;
    if( type==0 ) {
        p = texColor.r*0.2126 + texColor.g*0.7152 + texColor.b*0.0722;
    } else if( type == 1 ) {
        p = texColor.r;
    } else if( type == 2 ) {
        p = texColor.g;
    } else if( type == 3 ) {
        p = texColor.b;
    } else {
        adjOffs *= 0.0;
    }
    if( fromctr ) {
        p = (p-0.5)*2.0;
    }
    if( invert ) {
        adjOffs *= (1.0-p) * texColor.a;
    } else {
        adjOffs *= p * texColor.a;
    }
    vec2 sample = acScreenNorm + adjOffs;
    if(edges==0) {
        gl_FragColor = texture2DCv(comp.texture,sample);
    } else if(edges==1) {
        sample = vec2(1.0,1.0) - abs(mod(sample,vec2(2.0,2.0))-vec2(1.0,1.0));
        gl_FragColor = texture2DCv(comp.texture,sample) * texColor.a;
    } else if(edges==2) {
        if( sample.x < 0.0 || sample.x > 1.0 || sample.y < 0.0 || sample.y > 1.0 ) {
            gl_FragColor = vec4(0.0,0.0,0.0,0.0);
        } else {
            gl_FragColor = texture2DCv(comp.texture,sample) * texColor.a;
        }
    } else if(edges==3) {
        sample = mod(sample,vec2(1.0,1.0));
        gl_FragColor = texture2DCv(comp.texture,sample) * texColor.a;
    } else {
        gl_FragColor = texture2DCv(comp.texture,sample) * texColor.a;
    }

}
